import { Platform } from 'react-native';

// determine localhost address for Android emulator vs iOS/web
const LOCALHOST = Platform.OS === 'android' ? '10.0.2.2' : 'localhost';
// if running on a physical device, prefer LAN IP (override with EXPO_PUBLIC_DEV_HOST)
const DEV_HOST = process.env.EXPO_PUBLIC_DEV_HOST || (Platform.OS === 'android' ? '10.0.2.2' : '172.20.10.5');

// expose the current environment: "local" or "prod" ("staging" etc if you like)
export const APP_ENV = process.env.EXPO_PUBLIC_ENV || 'local';

// local and prod base URLs for the API
const API_BASE_URL_LOCAL =
  process.env.EXPO_PUBLIC_API_BASE_URL_LOCAL || `http://${DEV_HOST}:8081/api`;
const API_BASE_URL_PROD =
  process.env.EXPO_PUBLIC_API_BASE_URL_PROD || 'https://g-atelier-backend.onrender.com';

export const API_BASE_URL =
  (APP_ENV === 'prod' ? API_BASE_URL_PROD : API_BASE_URL_LOCAL).replace(/\/$/, '');

// frontend URL for OAuth redirects (web and mobile share same scheme)
const FRONTEND_BASE_URL_LOCAL =
  process.env.EXPO_PUBLIC_FRONTEND_BASE_URL_LOCAL || `http://${DEV_HOST}:3000`;
const FRONTEND_BASE_URL_PROD =
  process.env.EXPO_PUBLIC_FRONTEND_BASE_URL_PROD || 'https://g-atelier-front.onrender.com';

export const FRONTEND_BASE_URL =
  (APP_ENV === 'prod' ? FRONTEND_BASE_URL_PROD : FRONTEND_BASE_URL_LOCAL).replace(/\/$/, '');

export const OAUTH_REDIRECT_URL =
  process.env.EXPO_PUBLIC_OAUTH_REDIRECT_URL || `${FRONTEND_BASE_URL}/oauth2/redirect`;

// Database connection strings (this file lives in mobile but illustrates
// how you can switch databases on the backend). Keep the one you're using
// and comment the other; when PostgreSQL is ready you can uncomment the PG
// URL and comment out the MySQL one below.

